using System;

class Program
{
    static void Main()
    {
        string text = "  Merhaba Playground!  ";

        Console.WriteLine("Orijinal: '" + text + "'");
        Console.WriteLine("Trim: '" + text.Trim() + "'");
        Console.WriteLine("Buyuk harf: " + text.ToUpper());
        Console.WriteLine("Kucuk harf: " + text.ToLower());
        Console.WriteLine("Uzunluk: " + text.Length);

        string clean = text.Trim();
        Console.WriteLine("\nIceriyor mu 'Play': " + clean.Contains("Play"));
        Console.WriteLine("Baslangic 'Merhaba': " + clean.StartsWith("Merhaba"));

        // Bölme
        string sentence = "elma,armut,muz,karpuz";
        string[] fruits = sentence.Split(',');
        Console.WriteLine("\nMeyveler:");
        foreach (string fruit in fruits)
        {
            Console.WriteLine("- " + fruit);
        }

        // Birleştirme
        string joined = string.Join(" | ", fruits);
        Console.WriteLine("\nBirlestirilmis: " + joined);

        // Değiştirme
        string replaced = clean.Replace("Playground", "Dunya");
        Console.WriteLine("\nDegistirilmis: " + replaced);

        // String interpolation
        string name = "Zeynep";
        int score = 95;
        Console.WriteLine($"\n{name} sinavdan {score} puan aldi.");

        // Substring
        string sub = clean.Substring(0, 7);
        Console.WriteLine("\nIlk 7 karakter: " + sub);
    }
}
